INSERT INTO immigration_pathways (passport_slug, destination_slug, goal, pathway_name, summary, eligibility, key_requirements, typical_timeline, estimated_fees, pathway_type, processing_time, validity_period, last_updated)
VALUES

-- TURKEY
('any', 'turkey', 'Work', 'Work Permit (Çalışma İzni)',
 'Foreign nationals working in Turkey require a work permit from the Ministry of Family and Social Services. Turkey has a favorable geographic location at the crossroads of Europe and Asia, with a growing economy. Employer-sponsored work permits are the main pathway.',
 'Must have a job offer from a Turkish employer. The company must employ at least 5 Turkish nationals per 1 foreign worker. The foreign worker''s salary must be at least minimum wage (higher for specific roles). Permit is employer-tied.',
 'Employment contract, valid passport, employer''s company registration (ticaret sicil), educational qualifications, criminal background check, health insurance.',
 'Typically 4–8 weeks', 'USD 200–500 (varies by permit duration)',
 'work', '4–8 weeks', '1–3 years, renewable', CURRENT_DATE),

('any', 'turkey', 'Study', 'Student Residence Permit (Öğrenci İkamet İzni)',
 'International students studying at Turkish universities or educational institutions for 3+ months must obtain a student residence permit from the Directorate General of Migration Management (DGMM). Turkey has world-class universities and relatively low tuition fees.',
 'Must be enrolled at a recognized Turkish educational institution (accredited by YÖK — Council of Higher Education). Must have proof of financial means (approximately TRY 2,000–3,000/month). Must have health insurance.',
 'Enrollment certificate from Turkish institution, financial proof, health insurance, valid passport, biometric photos, rental contract or accommodation proof.',
 'Typically 2–4 weeks (DGMM application)', 'TRY 2,000–3,000',
 'study', '2–4 weeks', '1 year, renewable per academic year', CURRENT_DATE),

('any', 'turkey', 'Digital Nomad', 'Short-Term Residence Permit (Kısa Dönem)',
 'Turkey doesn''t have a dedicated digital nomad visa, but a Short-Term Residence Permit (valid 2 years renewable) is available for remote workers who can prove financial self-sufficiency. Turkey (especially Istanbul) is a growing digital nomad hub due to low costs and great infrastructure.',
 'Must have sufficient financial means to support yourself in Turkey without working for Turkish companies. Work for foreign companies in a remote capacity is in a legal grey area. Must have health insurance covering Turkey.',
 'Proof of financial means (bank statements showing USD 500+ per month), health insurance, valid passport, rental contract, clean criminal record, biometric photos.',
 'Typically 2–4 weeks (DGMM application after entering on a tourist or e-visa)', 'TRY 2,000–3,000',
 'digital_nomad', '2–4 weeks', '2 years, renewable', CURRENT_DATE),

('any', 'turkey', 'Retirement', 'Short-Term Residence Permit (Financially Independent)',
 'Retirees can obtain a Short-Term Residence Permit as financially independent persons. Turkey''s low cost of living, Mediterranean and Aegean coasts, and quality healthcare make it attractive. Property purchase also enables a residence permit.',
 'Must demonstrate sufficient passive income (pension, savings) for living costs in Turkey. Alternatively, purchasing property worth at least USD 200,000 qualifies for a real estate residence permit (and potentially Turkish citizenship via investment).',
 'Proof of income or savings, health insurance, valid passport, rental contract or property title deed, biometric photos.',
 'Typically 2–4 weeks', 'TRY 2,000–3,000 (property: additional costs apply)',
 'retirement', '2–4 weeks', '2 years, renewable', CURRENT_DATE),

('any', 'turkey', 'Investor', 'Turkish Citizenship by Investment (Turquoise Card)',
 'Turkey offers citizenship to investors who meet specific investment thresholds. The fastest route is a USD 400,000 real estate purchase or USD 500,000 in fixed capital investment. Turkey also has a Turquoise Card (similar to a green card) for highly skilled professionals and investors.',
 'Citizenship routes: USD 400,000 real estate (3-year hold); USD 500,000 in fixed capital investment or bank deposit; creating 50+ jobs for Turkish citizens; or USD 500,000 government bonds. Real estate is the most popular route.',
 'Investment documentation (property deed/share certificates), proof of funds and legitimate source, valid passport, criminal background check, health insurance, biometric photos.',
 'Typically 3–6 months (citizenship); 4–8 weeks (residence permit)', 'USD 500–1,500 (administrative fees)',
 'investor', '3–6 months', 'Turkish citizenship: lifetime', CURRENT_DATE),

('any', 'turkey', 'Family', 'Family Residence Permit (Aile İkamet İzni)',
 'Spouses and minor children of Turkish citizens or foreigners with valid Turkish residence permits can obtain a Family Residence Permit. Valid for the sponsor''s permit duration (up to 3 years renewable).',
 'Must be the spouse or unmarried child under 18 of: a Turkish citizen, OR a foreigner with a valid Turkish residence permit. Sponsor must have sufficient income and accommodation.',
 'Marriage certificate or birth certificate (apostilled and notarized Turkish translation), sponsor''s valid ID or residence permit, proof of income (minimum Turkish minimum wage × family members), accommodation proof, health insurance.',
 'Typically 2–4 weeks', 'TRY 2,000–3,000',
 'family', '2–4 weeks', 'Up to 3 years (matches sponsor''s permit duration)', CURRENT_DATE),

-- RUSSIA
('any', 'russia', 'Work', 'Work Visa + Temporary Residence Permit (RVP)',
 '⚠️ Due to the ongoing conflict in Ukraine and international sanctions, many countries'' nationals face restrictions on travelling to Russia, and banking/financial services access is extremely limited. This information is provided for general reference only. Verify current visa issuing status with the Russian embassy in your country.',
 'Must have a work invitation from a Russian employer who has obtained a "quota" from Russian regional authorities. Highly Qualified Specialists (HQS) can bypass the quota system with salaries above RUB 167,000/month (approximately USD 1,800).',
 'Work invitation from Russian employer, valid passport, criminal background check, medical tests (HIV, drug abuse), health insurance, migration card on entry, biometric photos.',
 'Typically 2–4 months (quota + visa + RVP)', 'USD 100–300',
 'work', '2–4 months', '1 year (work visa), then TRP/TP applications possible', CURRENT_DATE),

('any', 'russia', 'Study', 'Student Visa',
 '⚠️ Due to sanctions and the ongoing geopolitical situation, studying in Russia has become significantly more challenging for students from Western countries. This information is provided for reference. Russian universities offer scholarships through the Russian Government Scholarship program.',
 'Must be admitted to a Russian university or educational institution. Russian Government scholarships available for students from developing countries and CIS nations. Must have acceptable entry qualifications.',
 'Invitation letter from Russian university, valid passport, criminal background check, health insurance, biometric photos, HIV-negative certificate.',
 'Typically 4–8 weeks', 'RUB 1,600–3,500 (visa fee varies by nationality)',
 'study', '4–8 weeks', '1 year, renewable per academic year', CURRENT_DATE),

('any', 'russia', 'Digital Nomad', 'E-Visa / Tourist Visa',
 '⚠️ Russia''s e-visa program (previously covering select regions) has been significantly impacted by sanctions. Many Western country nationals have their Russian e-visa/visa programs suspended or severely restricted. Travelers should exercise extreme caution and check current advisories.',
 'Subject to current geopolitical restrictions. Previously, e-visas were available for 113 countries for up to 16-day single-entry stays. Most Western countries currently have limited or no regular visa service with Russia.',
 'Valid passport, invitation letter, return ticket, health insurance, sufficient funds.',
 'Varies significantly by nationality and current political situation', 'USD 50–300',
 'digital_nomad', 'Varies', 'Varies by visa type (generally 30–90 days tourist; multiple-entry up to 1 year)', CURRENT_DATE),

('any', 'russia', 'Retirement', 'Temporary Residence Permit (RVP) – Retiree',
 '⚠️ Geopolitical restrictions apply. For those who do qualify and wish to retire in Russia — typically CIS country nationals and specific bilateral agreement countries — a TRP (Temporary Residence Permit) can be obtained as a first step toward long-term residence.',
 'CIS country nationals and those with Russian-citizen spouses, parents, or children have priority pathways. Must have sufficient income for self-support. Western country nationals face significant barriers.',
 'Proof of income, health insurance, valid passport, documents establishing eligibility category.',
 'Typically 4–8 months', 'RUB 1,000–3,500',
 'retirement', '4–8 months', 'TRP: 3 years (then Permanent Residence possible after 1 year)', CURRENT_DATE),

('any', 'russia', 'Investor', 'Business Visa / Investor Permit',
 '⚠️ Significant sanctions and financial restrictions make business investment in Russia extremely difficult for Western nationals. Banking restrictions, SWIFT disconnections, and legal risks are severe. This is provided for informational reference only.',
 'Foreign business investors in Russia can apply for multi-entry business visas. Setting up a Russian company (ООО — LLC) allows for work authorization. Sanctions-affected nationals face near-complete barriers.',
 'Business invitation from Russian organization, company registration documents (if establishing a business), valid passport.',
 'Varies significantly', 'USD 100–500',
 'investor', 'Varies', 'Business visa: up to 1 year, multi-entry; TRP after establishing business', CURRENT_DATE),

('any', 'russia', 'Family', 'Family-Based Residence (RVP/RP)',
 'Foreign nationals with Russian citizen spouses, parents, or children can apply for a Temporary Residence Permit (RVP) outside the annual quota, and subsequently for Permanent Residence (RP).',
 'Must be legally married to a Russian citizen, OR have a Russian citizen parent or child. Marriage must be registered in Russia or recognized under Russian law.',
 'Marriage certificate or birth certificate (notarized Russian translation), Russian citizen''s passport, valid foreign passport, health certificates.',
 'Typically 4–6 months', 'RUB 1,000–3,500',
 'family', '4–6 months', 'TRP: 3 years; RP: 5 years (renewable)', CURRENT_DATE),

